transform_js:
const data = []; const categories = {};
// Create some dummy data to make it look dense
rawData.rows.forEach(r => {
  if(!categories[r.Category]) categories[r.Category] = [];
  categories[r.Category].push([r.Price, r.Mileage, r.Horsepower, r.Weight, r.Category]);
  for(let i=0; i<8; i++) {
     categories[r.Category].push([
        r.Price + (Math.random()-0.5)*2000,
        r.Mileage + (Math.random()-0.5)*4,
        r.Horsepower + (Math.random()-0.5)*20,
        r.Weight + (Math.random()-0.5)*300,
        r.Category
     ]);
  }
});
const seriesInfo = Object.keys(categories).map(cat => {
   return {
      name: cat,
      type: 'parallel',
      lineStyle: { width: 2, opacity: 0.5 },
      data: categories[cat]
   };
});
transformedData = seriesInfo;

echarts_js:
option = {
  title: {
    text: 'Car Specs (Parallel Coordinates)',
    left: 'center'
  },
  legend: {
    bottom: 0,
    data: transformedData.map(s => s.name)
  },
  tooltip: {
    padding: 10,
    backgroundColor: '#222',
    borderColor: '#777',
    borderWidth: 1
  },
  parallelAxis: [
    { dim: 0, name: 'Price ($)' },
    { dim: 1, name: 'Mileage (mpg)' },
    { dim: 2, name: 'Horsepower' },
    { dim: 3, name: 'Weight (lbs)' }
  ],
  parallel: {
    left: '5%',
    right: '13%',
    bottom: '10%',
    top: '20%',
    parallelAxisDefault: {
      type: 'value',
      nameLocation: 'end',
      nameGap: 20,
      nameTextStyle: {
        color: '#333',
        fontSize: 14
      },
      axisLine: { lineStyle: { color: '#aaa' } },
      axisTick: { lineStyle: { color: '#777' } },
      splitLine: { show: false },
      axisLabel: { color: '#333' }
    }
  },
  series: transformedData
};
